/**
 * Strategise for Personal Bests - Widget/PWA Icon Component
 * 
 * This file contains the Base64-encoded icon used for:
 *   - Browser tab favicon
 *   - Apple touch icon (home-screen widget)
 *   - PWA manifest icon
 *
 * Usage: Include this script in your HTML <head> before it is needed.
 *        It will automatically set the favicon, apple-touch-icon, and manifest.
 */

(function() {
    // The Base64-encoded favicon/widget icon (192x192 PNG)
    const FAVICON_BASE64 = "";

    // The Base64-encoded apple-touch-icon (180x180 PNG)
    const APPLE_TOUCH_ICON_BASE64 = "";

    // Set the favicon
    const faviconLink = document.createElement('link');
    faviconLink.rel = 'icon';
    faviconLink.type = 'image/png';
    faviconLink.href = 'data:image/png;base64,' + FAVICON_BASE64;
    document.head.appendChild(faviconLink);

    // Set the apple-touch-icon
    const appleTouchLink = document.createElement('link');
    appleTouchLink.rel = 'apple-touch-icon';
    appleTouchLink.href = 'data:image/png;base64,' + APPLE_TOUCH_ICON_BASE64;
    document.head.appendChild(appleTouchLink);

    // Set PWA meta tags
    const metaTags = [
        { name: 'apple-mobile-web-app-capable', content: 'yes' },
        { name: 'apple-mobile-web-app-status-bar-style', content: 'default' },
        { name: 'apple-mobile-web-app-title', content: 'Strategise' },
        { name: 'theme-color', content: '#ffffff' }
    ];

    metaTags.forEach(function(tag) {
        const meta = document.createElement('meta');
        meta.name = tag.name;
        meta.content = tag.content;
        document.head.appendChild(meta);
    });

    // Build and set the manifest
    const manifest = {
        name: 'Strategise for Personal Bests',
        short_name: 'Strategise',
        start_url: '.',
        display: 'standalone',
        background_color: '#ffffff',
        theme_color: '#4338ca',
        icons: [
            {
                src: 'data:image/png;base64,' + FAVICON_BASE64,
                sizes: '512x512',
                type: 'image/png'
            }
        ]
    };

    const manifestBlob = new Blob([JSON.stringify(manifest)], { type: 'application/json' });
    const manifestURL = URL.createObjectURL(manifestBlob);
    const manifestLink = document.createElement('link');
    manifestLink.rel = 'manifest';
    manifestLink.href = manifestURL;
    document.head.appendChild(manifestLink);
})();
